// 日本語の慣用句 → 英語の慣用句。定義じゃなくて、表現対表現。
// "English has no equivalent" なら削除。辞書的説明はNG。
// 1日10個、31日分 = 310個
// english = idiomを使った自然なフルセンテンス。

export interface NihongoEntry {
    daySlot: number;        // 1-31
    japanese: string;       // 図星
    english: string;        // full sentence, spoken level
    literal?: string;       // 直訳が面白い時だけ
    context?: string;       // 日本語の解説。なぜこの英語になるか、文化的・言語的ギャップ
    category: 'body' | 'nature' | 'food' | 'emotion' | 'action' | 'life';
    month?: string;         // '2026-03' etc. omitted = '2026-02' default
}

